import json, os

baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for proj in data['projects']:
        name = os.path.basename(proj['path'])
        pkgs = {}
        for fw in proj['frameworks']:
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = p['resolvedVersion']
        result[name] = pkgs
    return result

b = extract(baseline)
a = extract(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv != av:
            changes = True
            print(f'{proj} | {pkg} | {bv} -> {av}')
if not changes:
    print('(none)')

print()
print('=== UNCHANGED ===')
for proj in sorted(b.keys()):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(bp.keys()):
        if bp[pkg] == ap.get(pkg):
            print(f'{proj} | {pkg} | {bp[pkg]}')
